#include <iostream>
#include <cmath>

class Shape {
public:
    virtual double getArea() = 0;
    virtual ~Shape() = default;
};

class Rectangle : public Shape {
public:
    double wid;
    double hgt;
    Rectangle(double w, double h) : wid(w), hgt(h) {}
    double getArea() override { return wid * hgt; }
};

class Circle : public Shape {
public:
    double rad;
    Circle(double r) { rad = r; }
    double getArea() override {
        const double PI_VAL = 3.14159;
        return PI_VAL * rad * rad;
    }
};

int main() {
    Rectangle r1(5.0, 10.0);
    std::cout << r1.getArea() << std::endl;
    Circle c1(4.0);
    std::cout << c1.getArea() << std::endl;
    r1.wid = 7.0; r1.hgt = 2.0;
    std::cout << r1.getArea() << std::endl;
    c1.rad = 5.0;
    std::cout << c1.getArea() << std::endl;
    return 0;
}
